/**
 * OpenWA API Key Generator
 *
 * Generates a secure API key for OpenWA and prints it to stdout.
 * Usage: node scripts/generate-openwa-key.js
 *
 * Copy the output to your .env as OPENWA_API_KEY.
 *
 * The first admin key is auto-generated by OpenWA on first run
 * (printed to startup log and saved to data/.api-key).
 * This script generates a SwadKart-scoped key for integration.
 */

import crypto from "crypto";

const prefix = "owa_k1_";
const keyLength = 48;

const apiKey = prefix + crypto.randomBytes(keyLength).toString("hex");

console.log("\n🔑 OpenWA API Key (SwadKart Integration)");
console.log("─".repeat(50));
console.log(`\n${apiKey}\n`);
console.log("─".repeat(50));
console.log("\nAdd this to your .env file:\n");
console.log(`OPENWA_API_KEY=${apiKey}`);
console.log(`OPENWA_WEBHOOK_SECRET=${crypto.randomBytes(32).toString("hex")}\n`);
